import React, {Suspense} from "react";
import './App.css';
import Navbar from "./Components/Nav/Navbar";
import {BrowserRouter, Redirect, Route, Router, Switch, withRouter} from "react-router-dom";
// import DialogsContainer from "./Components/Dialogs/DialogsContainer";
import Footer from "./Components/Footer/Footer";
import UsersContainer from "./Components/Users/UsersContainer";
// import ProfileContainer from "./Components/Profile/ProfileContainer";
import HeaderContainer from "./Components/Header/HeaderContainer";
import Login from "./Components/Login/Login";
import {connect, Provider} from "react-redux";
import {compose} from "redux";
import {initializeApp} from "./redux/app-reducer";
import Preloader from "./Components/Common/Preloader/Preloader";
import store from "./redux/redux-store";
import {withSuspense} from "./Hoc/withSuspense";
import Preloader2 from "./Components/Common/Preloader/Preloader2";
import NavContainer from "./Components/Nav/NavContainer";
import Error from "./Components/404/404";

const DialogsContainer = React.lazy(() => import('./Components/Dialogs/DialogsContainer'));
const ProfileContainer = React.lazy(() => import('./Components/Profile/ProfileContainer'));


const Content = (props) => {
    return <div className='app-wrapper'>
        <HeaderContainer />
        <NavContainer />
        {/*<Footer/>*/}
        <div className='app-wrapper-content'>
            {/*с HOK <Route path='/dialogs' render={(withSuspense(DialogsContainer))}/>*/}
            <BrowserRouter>
            <Switch>
                <Suspense fallback={<Preloader2 />}>
                    {/*<Redirect from="/" to="/profile"/>*/}
                    {/*<Route exact path='/' render={() => <Redirect to={'/profile'}/>}/>*/}
                    <Route path='/dialogs' render={() => <DialogsContainer/>}/>
                    {/*//говорим что в урле м.б. параметр /:userId*/}
                    {/*//? говорит что доп параметр не обязательный*/}
                    <Route path='/profile/:userId?' render={() => <ProfileContainer/>}/>
                    <Route path='/users' render={() => <UsersContainer/>}/>
                    <Route path='/log' render={() => <Login/>}/>
                    <Route exact path={"/"} render={() => <Redirect to="/profile" />} />
                    <Route exact path="/404" component={Error} />
                    <Redirect to="/404" />



                    {/*/!*<Route path={"*"} render={() => <Redirect to="/music" />} />*!/*/}
                    {/*<Route exact path='*' render={() => <Footer/>} />*/}
                    {/*/!*<Redirect from='*' to ='/404'/>*!/*/}
                </Suspense>
            </Switch>
                </BrowserRouter>
        </div>
        {/*<Navbar />*/}
    </div>
}


export default Content;
